import{_ as p,c as e,o as r,ae as t}from"./chunks/framework.BvcDoAct.js";const m=JSON.parse('{"title":"Talk about BMSG - 16","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/16_RYUKI.md","filePath":"zh-cn/Management2Extra/01_TalkAboutBMSG/16_RYUKI.md"}'),o={name:"zh-cn/Management2Extra/01_TalkAboutBMSG/16_RYUKI.md"};function l(n,a,s,S,i,M){return r(),e("div",null,[...a[0]||(a[0]=[t('<p>整体翻译已经不错，但有一些语气、细节和准确性可以优化。我帮你整理成<strong>一版完全校对后的最终中文</strong>（已润色到更自然、贴近原文语感）：</p><h1 id="talk-about-bmsg-16" tabindex="-1">Talk about BMSG - 16 <a class="header-anchor" href="#talk-about-bmsg-16" aria-label="Permalink to &quot;Talk about BMSG - 16&quot;">​</a></h1><h2 id="ryuki-mazzel" tabindex="-1">RYUKI (MAZZEL) <a class="header-anchor" href="#ryuki-mazzel" aria-label="Permalink to &quot;RYUKI (MAZZEL)&quot;">​</a></h2><h3 id="即使想做的音乐不那么-像bmsg-也会被理解与支持。不被否定的环境成为团队的强项" tabindex="-1">即使想做的音乐不那么“像BMSG”，也会被理解与支持。不被否定的环境成为团队的强项 <a class="header-anchor" href="#即使想做的音乐不那么-像bmsg-也会被理解与支持。不被否定的环境成为团队的强项" aria-label="Permalink to &quot;即使想做的音乐不那么“像BMSG”，也会被理解与支持。不被否定的环境成为团队的强项&quot;">​</a></h3><p><em>RYUKI：2004年10月4日出生，福冈县出身</em></p><p><br><br><br> ————迄今为止，SKY-HI对你说过的话中，哪一句最让你印象深刻？</p><p>在演出前或者排练结束后，他给我提完建议之后，经常会对我说“RYUKI你一定可以做到”。我觉得这句话是不会对不信任的人说的，也正因为如此，它能让我更加有自信。带着“我一定可以”的想法站上舞台时，情绪投入会比平时强上一倍，也会让我觉得“也许可以这样去呈现”，从而拓宽表达的可能性。所以我真的觉得，社长的一句话分量非常大。</p><h3 id="没有-社长架子-的这一点-或许正是bmsg的魅力" tabindex="-1">没有“社长架子”的这一点，或许正是BMSG的魅力 <a class="header-anchor" href="#没有-社长架子-的这一点-或许正是bmsg的魅力" aria-label="Permalink to &quot;没有“社长架子”的这一点，或许正是BMSG的魅力&quot;">​</a></h3><p>————RYUKI在MAZZEL中经常负责rap部分，那么在rap方面，会经常接受SKY-HI的细致指导吗？</p><p>是的。他每次都会给我做指导，写歌词的时候也会一起商量。在不断交流意见的过程中，自然而然地拉近了和社长之间的距离。我们也会一起开玩笑，他对所有成员都很亲切。我觉得，正因为他在好的意义上完全没有那种“社长的架子”，这反而可能是BMSG最大的魅力之一。</p><p>————2024年MAZZEL举办了首次巡演，据说SKY-HI提出的主题是“成员之间要再亲近三个层次”。为了实现这一点，你有特别注意什么吗？</p><p>我其实没有特别去刻意注意什么。可能我是成员里面心态最自由的那一个吧。不会因为是在舞台上才特意去和成员互动，而是平时就像朋友一样每天待在一起，只是把这种关系呈现在舞台上表现出来而已。正因为没有刻意去做，反而我们经常一起去吃饭，休息的时候也几乎一直在一起，可以说基本上总是黏在一起。</p><p>————能感受到你把“保持自然”作为一种原则。另一方面，你在舞台上的爆发力也是很大的魅力，这本来就是你自带的吗？</p><p>是的。一站上舞台，不管场地大小，我都会进入一种“给我看MAZZEL！”的状态，整个人就会被点燃。</p><p>————巡演首日福冈场时，你说的那句MC“如果有人敢小看大家，我就把他狠狠干翻！”也受到了SKY-HI的高度评价。</p><p>是的（笑）。他说“那是很棒的MC。能够说出那种只有在舞台上才说得出来的话，很好。”那句话又给了我很大的自信，也让我觉得“以后就算在MC里情绪投入得再多一点也没问题”。</p><p>————如果要说你特别尊敬SKY-HI的地方，会是哪一点？</p><p>是他比任何人都更强烈的“对家人的爱”和“对音乐的爱”。所谓对家人的爱，就是像刚才说的那样，他会用很近的距离和我们相处，也会营造一个让人容易开口说话的环境。我真的觉得非常棒，这也是让我觉得“能在这家公司真是太好了”的地方。他大概是把我们所有人都当作自己的孩子来看待的吧。</p><p>有一次我们成员一起去他家做客，他一直说“因为有大家在”。我真的会觉得，“世界上是不是没有比他更温暖的人了”，也非常尊敬他那种重视伙伴的地方。</p><h3 id="总有一天-想成为能够超越社长的存在" tabindex="-1">总有一天，想成为能够超越社长的存在 <a class="header-anchor" href="#总有一天-想成为能够超越社长的存在" aria-label="Permalink to &quot;总有一天，想成为能够超越社长的存在&quot;">​</a></h3><p>————那在“对音乐的爱”方面，你具体尊敬他哪些地方？</p><p>他在创作音乐时的那种sense真的非常厉害。最近我们在MAZZEL的YouTube上传了一首叫《20years》的solo rap，我和他一起写歌词，当时真的被震撼到了。甚至让我忍不住想，“我们真的是用同一个人类的大脑在思考吗？”——他写出来的词，还有构建flow的方式，和我完全不一样。我一直忍不住在旁边说“太强了吧”（笑）。</p><p>正因为他本人对音乐充满热情，所以也会用同样的热情去对待BMSG这个“家族”，而且他是那种能够笔直地实现自己理想的人。我也很希望自己能拥有更多这样的特质，并且总有一天，想成为一个能够超越社长的存在。</p><p>————那反过来，有没有什么地方是你希望他可以改进的？</p><p>这是个很认真的“吐槽”——他吃饭真的太快了（笑）。之前一起合宿的时候，我都会忍不住紧张，“我得赶紧吃才行”。虽然我也知道他很忙没办法，但还是希望他能尽量吃慢一点！</p><p>————（笑）。也请说说最近在BMSG内部的交流吧。你和谁关系特别好？</p><p>一直以来关系很好的是BE:FIRST的SHUNTO。最近我刚满20岁，我们还在他家一起举杯庆祝了。我本来就很喜欢和各种人聊天，所以总部大楼建好之后，其实没什么太大变化……不过以前几乎没有机会和练习生（trainee）见面，自从大楼建好之后，交流变多了。比如一边泡着桑拿，一边看到成员在艺人休息室里和练习生一起打游戏的时候，就会由衷地觉得，“这真的是一家很棒的公司啊”。</p><p>————9月举办了“BMSG FES&#39;24”，在BMSG艺人的现场表演中，有没有特别印象深刻的？</p><p>BMSG MARINE的《Memoria》给我的冲击非常大。TAKUTO有一段solo舞蹈，我觉得特别帅，而且还带着一种性感。我自己其实也在走性感路线（笑），所以真的被激励到了，同时也为作为同一个团队的成员感到很自豪。BE:FIRST也非常厉害，solo艺人们则是各有各的个性，非常有意思。这次我是从舞台侧边设置的“沙龙”区域观看表演的，也再次感受到，BMSG真的是聚集了一群对音乐非常热爱的人。</p><p>————你这次是属于BMSG SKY队的。</p><p>平时我在MAZZEL大多是负责rap，但在SKY队的《Swan&#39;s War》里，我有负责副歌，更多是以唱歌为主。我觉得社长帮我挖掘出了一个新的自己。 能唱副歌这件事本身就让我很开心，同时也让我觉得，“原来我作为全能型选手也完全可以打得很强”。</p><p>————作为BMSG的一员，你最感到自豪的地方是什么？</p><p>是对个性的尊重。每个人喜欢的音乐和时尚都不一样，但社长全部都会给予肯定。</p><p>即使是我想做的rap风格，或者MAZZEL想做的音乐不那么“像BMSG”，他也会说“感觉会带来新的风啊”，愿意理解和支持我们。能够贴近我们想做的东西，这就是BMSG的优点，我觉得也会成为今后MAZZEL的一大强项。</p><p>————“THE LAST PIECE”也启动了，你有什么期待？</p><p>KANON是在《MISSIONx2》里和我一起经历过艰难审查的伙伴，RUI和TAIKI则是在进入BMSG之后很快就熟络起来，现在也经常一起打游戏。我是打从心底在为他们应援。同时，因为MAZZEL之后会诞生新的组合，我们自己也会觉得“必须更加努力了”，不过家族成员增加这件事本身让我很开心，也会好奇会来什么样的人——真的很想一起玩！</p><hr><blockquote><h3 id="from-sky-hi" tabindex="-1">from SKY-HI <a class="header-anchor" href="#from-sky-hi" aria-label="Permalink to &quot;from SKY-HI&quot;">​</a></h3><p>如果我能为他创造一个可以随心所欲闪耀的地方，那对我来说也是一种幸福的复仇。</p><p>也有人会把他那种让人一刻都移不开视线的魅力，当作“Kawaii”而产生某种抗拒，</p><p>但他是在内心拥有强大力量的同时，依然没有失去那份魅力地活着，这一点真的非常帅气。我由衷地尊敬他，也很憧憬。</p><p>我和RYUKI的相遇，是为了证明“有rapper存在的组合可以如此闪耀”。这是必然的（笑）。</p></blockquote>',38)])])}const b=p(o,[["render",l]]);export{m as __pageData,b as default};
